if (msg.payload && msg.payload.type === 'command') {
    // Re-structure the message for the auth flow
    msg.token = msg.payload.token;
    msg.payload = msg.payload.data;
    return msg;
}
// If it's not a command message, stop the flow.
return null;

// Output 1 -> WebSocket Out (dashboard)
// Output 2 -> HTTP Response (ACK to caller)

// keep original payload to forward to dashboard
const forward = { ...msg };

// Prepare an immediate HTTP ack
const ack = {
  ...msg,
  statusCode: 200,
  headers: {
    "Content-Type": "application/json; charset=utf-8"
  },
  payload: {
    ok: true,
    received: true,
    ts: Date.now()
  }
};

// Send to WS (output 1) and finish HTTP request (output 2)
return [forward, ack];

// FIX 1: Save command data BEFORE overwriting msg.payload.
// Parse WS Command sets msg.payload = command data (stationid, action, etc.)
// and msg.token = Firebase ID token. We must preserve the command data here
// or it will be lost when msg.payload is overwritten for the HTTP verify call.
if (!msg.command) {
  msg.command = msg.payload;
}

// Token arrives from WS message (msg.token) or HTTP header
const token = msg.token ||
  (msg.req?.headers?.authorization || '').replace('Bearer ', '');

if (!token) {
  // No token - log and stop. Legitimate commands always include a token.
  node.warn('Command received with no token - ignoring');
  return null;
}

// Check flow-level cache to avoid a Firebase round-trip on every command
const cache = flow.get('tokenCache') || {};
const cached = cache[token];
if (cached && cached.expires > Date.now()) {
  msg.payload = cached.user;
  return [msg, null]; // cache hit -> output 1 (Authorize)
}

msg._fbToken = token;
msg.payload = { idToken: token };
msg.headers = { 'Content-Type': 'application/json' };
return [null, msg]; // cache miss -> output 2 (HTTP verify)

// Check Firebase returned a valid user
if (!msg.payload?.users?.length) {
  node.send([null, { ...msg, statusCode: 401, payload: { error: 'invalid_token' } }]);
  return null;
}

try {
  const firebaseUser = msg.payload.users[0];

  // Custom claims are stored in customAttributes by the Firebase Admin SDK (syncCustomClaims)
  let claims = {};
  try { claims = JSON.parse(firebaseUser.customAttributes || '{}'); } catch (_) {}

  const user = {
    uid:      firebaseUser.localId || '',
    username: claims.username || '',
    clientId: claims.clientId || '',
    role:     claims.role     || 'user',
    commands: claims.commands || {},
  };

  // Cache for 55 min (Firebase ID tokens expire in 60 min; 5 min safety margin)
  const cache = flow.get('tokenCache') || {};
  const now = Date.now();
  cache[msg._fbToken] = { user, expires: now + (55 * 60 * 1000) };
  // Evict expired entries
  Object.keys(cache).forEach(k => { if (cache[k].expires < now) delete cache[k]; });
  flow.set('tokenCache', cache);

  msg.payload = user;
  return [msg, null]; // success -> output 1 (Authorize Command)
} catch (e) {
  node.send([null, { ...msg, statusCode: 401, payload: { error: 'invalid_token' } }]);
  return null;
}

const user = msg.payload;
const command = msg.command;
const allKiosks = global.get('info') || [];

// Admins can do everything
if (user.role === 'admin' || user.username === 'chargerent') {
  return [msg, null];
}

// Map raw command action to the permission key stored in user.commands
const ACTION_TO_PERMISSION = {
  'eject specific': 'eject', 'eject all': 'eject', 'eject full': 'eject',
  'eject empty': 'eject', 'eject locked': 'eject', 'eject module': 'eject',
  'eject count': 'eject', 'rent': 'eject', 'refund': 'eject',
  'lock slot': 'lock', 'unlock slot': 'lock',
  'reboot': 'reboot',
  'reload ui': 'reload',
  'ngrok connect': 'connectivity', 'ngrok disconnect': 'connectivity', 'hotspot': 'connectivity',
  'update flow': 'updates', 'update ui': 'updates',
  'disable': 'disable', 'enable': 'disable',
  'infochange': 'client edit', 'hardwarechange': 'client edit',
  'pricechange': 'client edit', 'uichange': 'client edit',
  'provision': 'edit',
};

const requiredPerm = ACTION_TO_PERMISSION[command?.action];
const userCommands = user.commands || {};

// Check clientId matches kiosk's client or rep
const targetKiosk = allKiosks.find(k => k?.stationid === command?.stationid);
const userClientId = String(user.clientId || '').trim();

if (!targetKiosk?.info) {
  node.send([null, { _session: msg._session, payload: { status: 'error', reason: 'Kiosk not found' } }]);
  return null;
}

const kioskClient = String(targetKiosk.info.client || '').trim();
const kioskRep    = String(targetKiosk.info.rep || '').trim();
const clientMatch = !!(userClientId && (kioskClient === userClientId || kioskRep === userClientId));

if (!clientMatch) {
  node.send([null, { _session: msg._session, payload: { status: 'error', reason: 'Unauthorized' } }]);
  return null;
}

// Check specific command permission
if (requiredPerm && userCommands[requiredPerm] !== true) {
  node.send([null, { _session: msg._session, payload: { status: 'error', reason: 'Permission denied' } }]);
  return null;
}

return [msg, null];
